    private function plumbing(): array
    {
        return [
            ['type' => 'section', 'heading' => 'Plumbing Service Overview', 'body' => "Plumbing problems never happen at a convenient time. A burst pipe at 2 AM, a water heater that dies on a holiday weekend, or a slow leak that has been hiding behind your walls — our licensed plumbers show up fast and fix it right.\n\nWe handle everything from routine repairs to full repiping projects. Every job gets a clear, flat-rate quote before we start. No hourly billing, no hidden fees, and no upsells on parts you do not need."],
            ['type' => 'section', 'heading' => 'Why Plumbing Maintenance Matters', 'body' => "Staying ahead of plumbing problems protects your home and your wallet. A little preventive care goes a long way.\n\nPrevent Costly Water Damage — Catching a small drip or hidden leak early stops it from becoming a flooded basement, ruined drywall, or a mold problem that costs thousands to fix.\n\nProtect Your Water Quality — Routine checks keep pipes, water heaters, and fixtures free of buildup and corrosion, so the water reaching your taps stays clean and safe.\n\nExtend the Life of Your System — Flushing your water heater and inspecting your pipes keeps everything running longer, delaying the cost of major replacements for years."],
            ['type' => 'image', 'heading' => 'Guardian Air plumber working on pipes in a New Jersey home', 'image_path' => '/img/plumbing-hero.webp'],
            ['type' => 'section', 'heading' => 'Signs You Need A Plumber', 'body' => "Small plumbing issues rarely fix themselves. Keep an eye out for these warning signs.\n\nLow Water Pressure — A sudden drop in pressure often points to a hidden leak, a clog, or corrosion building up inside your pipes that needs attention.\n\nPersistent Drips & Leaks — A dripping faucet or a leak under the sink wastes water and signals worn seals or fittings that will only get worse over time.\n\nSlow or Backed-Up Drains — Drains that empty slowly or gurgle usually mean a clog or a deeper blockage in the line that a plunger will not fix.\n\nDiscolored or Smelly Water — Rusty, cloudy, or foul-smelling water is a sign of corroded pipes or a failing water heater that should be inspected right away.\n\nNoticing any of these? Schedule a plumbing inspection and we'll find and fix the problem fast."],
            ['type' => 'section', 'heading' => 'Plumbing Services We Offer', 'body' => "Here's a quick guide to the plumbing services our licensed team provides.\n\nLeak Detection & Repair — We pinpoint hidden leaks behind walls and under floors with no guesswork, then fix the source before it causes water damage.\n\nWater Heater Service — Repair, replacement, and installation of traditional tank and tankless water heaters for reliable hot water all year.\n\nPipe Replacement & Repiping — From a single corroded section to a full home repipe, we replace failing pipes with durable, long-lasting materials.\n\nDrain & Sewer Cleaning — Fast clearing of clogged drains and main sewer lines using professional tools that protect your pipes.\n\nEmergency Plumbing — Burst pipes, overflowing toilets, and no-water emergencies handled with same-day, around-the-clock response."],
            ['type' => 'faq', 'heading' => 'How do I know if I have a hidden water leak?', 'body' => 'Watch for an unexplained jump in your water bill, the sound of running water when everything is off, damp spots or stains on walls and ceilings, or a musty smell. We use professional leak detection to find the source without tearing up your home.'],
            ['type' => 'faq', 'heading' => 'How long does a water heater last?', 'body' => 'A traditional tank water heater typically lasts 8 to 12 years, while a tankless unit can run 20 years or more with proper maintenance. If yours is near the end of its life or needs frequent repairs, replacement is usually the smarter investment.'],
            ['type' => 'faq', 'heading' => 'Why do my drains keep clogging?', 'body' => 'Recurring clogs are usually caused by grease buildup, hair, soap scum, or tree roots in the main line. A one-time clear may not solve a deeper blockage, so we inspect the line to find and fix the real cause.'],
            ['type' => 'faq', 'heading' => 'What should I do during a plumbing emergency?', 'body' => 'Shut off the water supply right away — either the fixture valve or your main shutoff — to limit the damage, then call us. We offer same-day emergency service for burst pipes, major leaks, and overflowing fixtures.'],
            ['type' => 'faq', 'heading' => 'Can I fix a leaky faucet myself?', 'body' => 'A simple washer or cartridge swap is fine for a handy homeowner. But if the leak keeps coming back, the fixture is corroded, or you spot water under the sink, it is worth having a licensed plumber take a look before it gets worse.'],
            ['type' => 'faq', 'heading' => 'How much does plumbing repair cost?', 'body' => 'It depends on the job, but we always give you a clear, flat-rate quote before any work begins. No hourly billing, no hidden fees, and no surprise charges once the work is done.'],
            ['type' => 'faq', 'heading' => 'Is a tankless water heater worth it?', 'body' => 'For many homes, yes. Tankless units heat water on demand, never run out during long showers, take up far less space, and last longer than tank models. We can help you decide if one fits your home and budget.'],
            ['type' => 'faq', 'heading' => 'Why is my water pressure suddenly low?', 'body' => 'Low pressure can come from a hidden leak, mineral buildup in the pipes, a failing pressure regulator, or an issue with the municipal supply. A quick diagnostic visit will pinpoint the exact cause.'],
            ['type' => 'faq', 'heading' => 'Do you offer repiping for older homes?', 'body' => 'Yes. Many older New Jersey homes still have aging galvanized or polybutylene pipes that corrode and leak. We replace them with modern, long-lasting materials to restore safe, reliable water flow.'],
            ['type' => 'faq', 'heading' => 'Are your plumbers licensed and insured?', 'body' => 'Absolutely. Every Guardian Air plumber is fully licensed, insured, and bonded, so you get safe, code-compliant work backed by a guarantee on every visit.'],
        ];
    }

    private function electrical(): array
    {
        return [
            ['type' => 'section', 'heading' => 'Electrical Service Overview', 'body' => "Electrical work is not a DIY project. Whether you need a panel upgrade to handle modern appliances, new outlets for a home office, or emergency repairs for a tripped breaker, our licensed electricians deliver safe, code-compliant work every time.\n\nWe handle residential and light commercial electrical projects of all sizes. Every job starts with a thorough inspection and a flat-rate quote. We explain what needs to be done, why it matters for your safety, and what it will cost — before we touch a single wire."],
            ['type' => 'section', 'heading' => 'Why Electrical Safety Matters', 'body' => "Your home's electrical system powers everything you rely on, and when it's neglected, the risks add up fast. Staying on top of it protects your home and your family.\n\nPrevent Electrical Fires — Faulty wiring and overloaded circuits are a leading cause of home fires. Regular inspections catch hidden hazards before they become dangerous.\n\nProtect Your Appliances — Proper wiring and surge protection shield your electronics and appliances from damaging power spikes, extending their lifespan.\n\nStay Code-Compliant — Outdated or DIY wiring can fail inspection and void insurance. Licensed work keeps your home up to current electrical code and safe for your family."],
